import{_ as t,H as o,f as n,i}from"./chunks/framework.DihYizOb.js";const u=JSON.parse('{"title":"The Flat Universe","description":"","frontmatter":{},"headers":[],"relativePath":"The-Flat-Universe.md","filePath":"The-Flat-Universe.md"}'),a={name:"The-Flat-Universe.md"};function r(s,e,c,p,l,d){return o(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="the-flat-universe" tabindex="-1">The Flat Universe <a class="header-anchor" href="#the-flat-universe" aria-label="Permalink to &quot;The Flat Universe&quot;">​</a></h1><p>Reality has one primitive: <strong>distinction.</strong></p><p><code>0 / 1</code> · <code>A / not-A</code> · <code>occupy / not occupy</code></p><p><strong>Everything computable is built from that.</strong> Hierarchy is not fundamental. It is emergent. Dimensions, geometry, complexity, consciousness — all are iterations of a binary decision.</p><p><strong>Movement is change of occupation.</strong></p><p><code>A → not-A</code></p><p>The base needs no purpose. No intention. No direction. Only one rule: <strong>allow distinction.</strong></p><blockquote><p><strong>If you can compute it, you cannot lose it.</strong><strong>Everything that is possible, is allowed.</strong></p></blockquote><p><code>distinction → information → geometry → landscape</code></p><hr><p>This is why cleaker operates from a flat namespace tree rather than a strict hierarchy. The tree is a convenience for routing — not a statement about reality. Identity is not &quot;above&quot; or &quot;below&quot; context. Identity <strong>is</strong> the binding to context.</p><p><code>cleaker(me)</code> — one operation. One primitive.</p>',12)])])}const m=t(a,[["render",r]]);export{u as __pageData,m as default};
